use std::net::UdpSocket;
use std::io;

fn main() -> io::Result<()> {
    let local_addr = "127.0.0.1:8080";
    let peer_addr = "127.0.0.1:8081";

    let socket = UdpSocket::bind(local_addr)?;
    println!("Listening on {}", local_addr);

    socket.recv_from(&mut [0; 1024])?;

    let message = b"Kyber key material payload";
    println!("Sending message to {}", peer_addr);
    socket.send_to(message, peer_addr)?;

    let mut buffer = [0; 1024];
    match socket.recv_from(&mut buffer) {
        Ok((size, _)) => {
            println!("Successfully received {} bytes: {}", size, String::from_utf8_lossy(&buffer[..size]));
        }
        Err(e) => {
            eprintln!("Failed to receive data: {}", e);
        }
    }

    Ok(())
}

use std::net::{UdpSocket};

fn main() -> std::io::Result<()> {
    let local_addr = "127.0.0.1:8080";
    let remote_addr_str = "127.0.0.1:9090";

    let socket = UdpSocket::bind(local_addr)?;

    let data_to_send = b"Transaction: SET key_id value_data timestamp:1678886400";

    println!("Sending log entry to {}", remote_addr_str);
    socket.send_to(data_to_send, remote_addr_str)?;

    let mut buf = [0; 1024];
    const TIMEOUT_SECS: std::time::Duration = std::time::Duration::from_secs(5);

    socket.set_read_timeout(Some(TIMEOUT_SECS))?;

    println!("Waiting for acknowledgement from {}", remote_addr_str);
    match socket.recv_from(&mut buf) {
        Ok((len, src)) => {
            let ack = String::from_utf8_lossy(&buf[..len]);
            println!("Successfully received acknowledgement from {}: {}", src, ack);
        },
        Err(e) => {
            if e.kind() == std::io::ErrorKind::TimedOut {
                eprintln!("Error: Operation timed out waiting for confirmation.");
            } else {
                eprintln!("An error occurred while receiving data: {}", e);
            }
        }
    }

    Ok(())
}

use std::io::{self, Result};
use std::net::UdpSocket;
use std::sync::Arc;
use tokio::net::UdpSocket as TokioUdpSocket;
use std::time::Duration;

const LOCAL_ADDR: &str = "127.0.0.1:8080";
const BUFFER_SIZE: usize = 1024;

async fn process_ingestion_block(data: &[u8]) {
    println!("Processing data block of size {}", data.len());
}

#[tokio::main]
async fn main() -> Result<()> {
    let socket = TokioUdpSocket::bind(LOCAL_ADDR).await?;
    let socket_arc = Arc::new(socket);

    println!("Listening on {}:8080. Send test data to it.", LOCAL_ADDR);

    loop {
        let mut buf = [0u8; BUFFER_SIZE];
        match socket_arc.recv_from(&mut buf).await {
            Ok((size, src)) => {
                let data = &buf[..size];
                println!("nReceived {} bytes from {}", size, src);
                process_ingestion_block(data).await;
            }
            Err(e) => {
                eprintln!("Error receiving data: {}", e);
            }
        }
    }
}

use std::net::{UdpSocket, SocketAddr};
use std::sync::Arc;
use std::thread;
use std::time::Duration;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let local_addr = "127.0.0.1:8080".parse::<SocketAddr>()?;
    let remote_broadcast = "255.255.255.255:9000".parse::<SocketAddr>()?;

    println!("Attempting to broadcast configuration update...");

    let socket = UdpSocket::bind(local_addr)?;

    let config_object_state = b"{ \"user\": \"dev\", \"service\": \"dotfile_manager\", \"version\": 2.1 }";

    let mut count = 0;
    const MAX_ATTEMPTS: usize = 3;

    for attempt in 0..MAX_ATTEMPTS {
        println!("Sending broadcast attempt {}...", attempt + 1);
        match socket.send_to(config_object_state, remote_broadcast) {
            Ok(_) => {
                count += 1;
                thread::sleep(Duration::from_millis(50));
            },
            Err(e) => {
                println!("Warning: Failed to send packet on attempt {}: {}", attempt + 1, e);
            }
        }
    }

    if count > 0 {
        println!("Successfully initiated {} broadcast attempts.", count);
    } else {
        println!("No packets were sent across all attempts.");
    }

    Ok(())
}
